                userId={user.id}
                info={user.info}
                isSelf={isSelf}
                zIndex={100 - index}
              />
            );
          })}

          {overflowCount > 0 && (
            <div
              data-testid="avatar-overflow"
              style={{
                width: 32,
                height: 32,
                borderRadius: "50%",
                backgroundColor: "#e5e7eb",
                border: "2px solid #fff",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                marginLeft: -8,
                fontSize: 12,
                fontWeight: 600,
                color: "#374151",
                zIndex: 0,
              }}
            >
              +{overflowCount}
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
